mapper.select:
SELECT store_id, name, address, phone, opened_at, is_active AS active, created_at
FROM stores
WHERE store_id = #{storeId}

mapper.update:
UPDATE stores
SET name = #{name}, address = #{address}, phone = #{phone}
WHERE store_id = #{storeId}

UPDATE staff
SET name = #{name}, phone = #{phone}
WHERE staff_id = #{staffId}

UPDATE auth_users
SET hashed_password = #{hashedPassword}
WHERE staff_id = #{staffId}
